// Validate and extract employers_general_data payload
const body = $input.first().json.body || $input.first().json;

if (!body.data || !body.data.source || !body.data.source.itens) {
  throw new Error('Missing required structure: data.source.itens');
}

const itens = body.data.source.itens;

if (!Array.isArray(itens) || itens.length === 0) {
  throw new Error('itens must be a non-empty array');
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_general_data_received',
  count: itens.length
}));

return { itens };

// Split itens into individual records for batch processing
const data = $input.first().json;
const itens = data.itens;

return itens.map(item => ({
  record: item
}));

// Build success response
const allItems = $input.all();
const updatedCount = allItems.filter(item => item.json.matricula_funcionario).length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_general_data_completed',
  updated_count: updatedCount
}));

return {
  statusCode: 201,
  body: {
    status: 'success',
    message: 'Employers general data processed successfully.'
  }
};
